function validateField(value, fieldDef, fieldName) {
  if (value === undefined || value === null) {
    return { valid: false, error: `Field '${fieldName}' is null or undefined` };
  }

  if (fieldDef.type === 'string') {
    if (typeof value !== 'string') {
      return { valid: false, error: `Field '${fieldName}' must be a string` };
    }
    if (fieldDef.maxLength && value.length > fieldDef.maxLength) {
      return { valid: false, error: `Field '${fieldName}' exceeds max length ${fieldDef.maxLength}` };
    }
    if (fieldDef.pattern && !fieldDef.pattern.test(value)) {
      return { valid: false, error: `Field '${fieldName}' does not match required pattern` };
    }
    if (fieldDef.enum && !fieldDef.enum.includes(value)) {
      return { valid: false, error: `Field '${fieldName}' must be one of: ${fieldDef.enum.join(', ')}` };
    }
  } else if (fieldDef.type === 'number') {
    if (typeof value !== 'number' || !Number.isFinite(value)) {
      return { valid: false, error: `Field '${fieldName}' must be a finite number` };
    }
    if (fieldDef.min !== undefined && value < fieldDef.min) {
      return { valid: false, error: `Field '${fieldName}' below minimum ${fieldDef.min}` };
    }
    if (fieldDef.max !== undefined && value > fieldDef.max) {
      return { valid: false, error: `Field '${fieldName}' above maximum ${fieldDef.max}` };
    }
  } else if (fieldDef.type === 'array') {
    if (!Array.isArray(value)) {
      return { valid: false, error: `Field '${fieldName}' must be an array` };
    }
    if (fieldDef.maxLength && value.length > fieldDef.maxLength) {
      return { valid: false, error: `Field '${fieldName}' exceeds max array length ${fieldDef.maxLength}` };
    }
  } else if (fieldDef.type === 'object') {
    if (typeof value !== 'object' || value === null || Array.isArray(value)) {
      return { valid: false, error: `Field '${fieldName}' must be a plain object` };
    }
    if (fieldDef.maxKeys && Object.keys(value).length > fieldDef.maxKeys) {
      return { valid: false, error: `Field '${fieldName}' has too many keys` };
    }
    // Ensure all values in the object are primitives (no nested injection vectors)
    for (const [k, v] of Object.entries(value)) {
      if (typeof k !== 'string' || k.length > 100) {
        return { valid: false, error: `Field '${fieldName}' contains invalid key` };
      }
      if (typeof v !== 'string' && typeof v !== 'number' && typeof v !== 'boolean') {
        return { valid: false, error: `Field '${fieldName}.${k}' must be a primitive value` };
      }
      if (typeof v === 'string' && v.length > 1000) {
        return { valid: false, error: `Field '${fieldName}.${k}' value too long` };
      }
    }
  }

  return { valid: true };
}

function validateMessage(message) {
  // Check message type is in allowlist
  if (!message.type || typeof message.type !== 'string') {
    return { valid: false, error: 'Missing or invalid message type' };
  }

  if (!ALLOWED_MESSAGE_TYPES.has(message.type)) {
    return { valid: false, error: `Unknown message type: ${message.type}` };
  }

  const schema = MESSAGE_SCHEMAS[message.type];
  if (!schema) {
    return { valid: false, error: `No schema defined for message type: ${message.type}` };
  }

  if (!message.payload || typeof message.payload !== 'object' || Array.isArray(message.payload)) {
    return { valid: false, error: 'Payload must be a plain object' };
  }

  // Check for unexpected fields in payload (only allow defined fields)
  const allowedFields = new Set(Object.keys(schema.fields));
  for (const key of Object.keys(message.payload)) {
    if (!allowedFields.has(key)) {
      return { valid: false, error: `Unexpected field in payload: ${key}` };
    }
  }

  // Check required fields
  for (const field of schema.required) {
    if (message.payload[field] === undefined || message.payload[field] === null) {
      return { valid: false, error: `Missing required field: ${field}` };
    }
  }

  // Validate each field
  for (const [fieldName, fieldDef] of Object.entries(schema.fields)) {
    const value = message.payload[fieldName];
    if (value === undefined) continue; // Optional field not present

    const result = validateField(value, fieldDef, fieldName);
    if (!result.valid) {
      return result;
    }

    // Special validation for order items array
    if (fieldName === 'items' && Array.isArray(value)) {
      for (let i = 0; i < value.length; i++) {
        const item = value[i];
        if (typeof item !== 'object' || item === null || Array.isArray(item)) {
          return { valid: false, error: `items[${i}] must be a plain object` };
        }
        // Check for unexpected fields in item
        const allowedItemFields = new Set(Object.keys(ORDER_ITEM_SCHEMA.fields));
        for (const key of Object.keys(item)) {
          if (!allowedItemFields.has(key)) {
            return { valid: false, error: `Unexpected field in items[${i}]: ${key}` };
          }
        }
        for (const reqField of ORDER_ITEM_SCHEMA.required) {
          if (item[reqField] === undefined) {
            return { valid: false, error: `items[${i}] missing required field: ${reqField}` };
          }
        }
        for (const [itemFieldName, itemFieldDef] of Object.entries(ORDER_ITEM_SCHEMA.fields)) {
          if (item[itemFieldName] === undefined) continue;
          const itemResult = validateField(item[itemFieldName], itemFieldDef, `items[${i}].${itemFieldName}`);
          if (!itemResult.valid) return itemResult;
        }
      }
    }
  }

  // Validate optional metadata
  if (message.correlationId !== undefined) {
    if (typeof message.correlationId !== 'string' || !/^[a-f0-9-]{36}$/.test(message.correlationId)) {
      return { valid: false, error: 'Invalid correlationId format' };
    }
  }

  if (message.timestamp !== undefined) {
    if (typeof message.timestamp !== 'string' || isNaN(Date.parse(message.timestamp))) {
      return { valid: false, error: 'Invalid timestamp format' };
    }
  }

  return { valid: true };
}

function safeParseJSON(raw) {
  try {
    // Protect against prototype pollution
    const parsed = JSON.parse(raw);
    if (parsed && typeof parsed === 'object') {
      // Remove __proto__ and constructor to prevent prototype pollution
      delete parsed.__proto__;
      delete parsed.constructor;
      delete parsed.prototype;
      if (parsed.payload && typeof parsed.payload === 'object') {
        delete parsed.payload.__proto__;
        delete parsed.payload.constructor;
        delete parsed.payload.prototype;
      }
    }
    return { success: true, data: parsed };
  } catch (err) {
    return { success: false, error: err.message };
  }
}

