    const client = await pool.connect();
    try {
      await client.query('BEGIN');
      await client.query(
        'INSERT INTO orders (id, user_id, total_amount, status, created_at) VALUES ($1, $2, $3, $4, NOW())',
        [orderId, userId, totalAmount, 'pending']
      );

      for (const item of items) {
        const itemId = randomUUID();
        await client.query(
          'INSERT INTO order_items (id, order_id, product_id, quantity, price) VALUES ($1, $2, $3, $4, $5)',
          [itemId, orderId, item.productId, item.quantity, item.price]
        );
      }

      await client.query('COMMIT');
    } catch (err) {
      await client.query('ROLLBACK');
      throw err;
    } finally {
      client.release();
    }
    await logEvent('order.created', orderId, { userId, totalAmount, itemCount: items.length }, correlationId);
    console.log(`[order.created] Order ${orderId} created with ${items.length} items`);
