async function logEvent(eventType, entityId, data, correlationId) {
  try {
    await pool.query(
      'INSERT INTO event_log (id, event_type, entity_id, data, correlation_id, created_at) VALUES ($1, $2, $3, $4, $5, NOW())',
      [randomUUID(), eventType, entityId, JSON.stringify(data), correlationId || null]
    );
  } catch (err) {
    console.error('Failed to log event:', err.message);
  }
}

// --- Dead Letter / Retry Logic ---

async function sendToDeadLetter(channel, msg, error) {
  try {
    const dlxExchange = process.env.DLX_EXCHANGE || 'events.dlx';
    const errorInfo = {
      originalContent: msg.content.toString('utf8').substring(0, 1000),
      error: error.message || String(error),
      timestamp: new Date().toISOString(),
      queue: process.env.QUEUE_NAME || 'events_queue',
    };
    channel.publish(
      dlxExchange,
      'dead-letter',
      Buffer.from(JSON.stringify(errorInfo)),
      { persistent: true }
    );
  } catch (dlErr) {
    console.error('Failed to send to dead letter queue:', dlErr.message);
  }
}

// --- Main Consumer ---

async function startConsumer() {
  const rabbitmqUrl = process.env.RABBITMQ_URL || 'amqp://localhost';
  const queueName = process.env.QUEUE_NAME || 'events_queue';
  const prefetchCount = parseInt(process.env.PREFETCH_COUNT, 10) || 10;

  let connection;
  let channel;

  try {
    connection = await amqplib.connect(rabbitmqUrl);
    channel = await connection.createChannel();

    // Set prefetch to avoid overwhelming the service
    await channel.prefetch(prefetchCount);

    // Assert queue exists with dead-letter exchange configuration
    await channel.assertExchange('events.dlx', 'direct', { durable: true });
    await channel.assertQueue('events_dead_letter', { durable: true });
    await channel.bindQueue('events_dead_letter', 'events.dlx', 'dead-letter');

    await channel.assertQueue(queueName, {
      durable: true,
      arguments: {
        'x-dead-letter-exchange': 'events.dlx',
        'x-dead-letter-routing-key': 'dead-letter',
        'x-message-ttl': 86400000, // 24 hour TTL
      },
    });

    console.log(`[*] Waiting for messages in queue: ${queueName}`);

    channel.consume(queueName, async (msg) => {
      if (!msg) return;

      const rawContent = msg.content.toString('utf8');

      // 1. Check message size
      if (rawContent.length > MAX_PAYLOAD_SIZE) {
        console.error(`[REJECTED] Message exceeds max size (${rawContent.length} bytes)`);
        channel.nack(msg, false, false); // Don't requeue
        return;
      }

      // 2. Safe JSON parse
      const parseResult = safeParseJSON(rawContent);
      if (!parseResult.success) {
        console.error(`[REJECTED] Invalid JSON: ${parseResult.error}`);
        channel.nack(msg, false, false);
        return;
      }

      const message = parseResult.data;

      // 3. Validate message structure and payload against schema
      const validation = validateMessage(message);
      if (!validation.valid) {
        console.error(`[REJECTED] Validation failed: ${validation.error}`);
        await sendToDeadLetter(channel, msg, new Error(validation.error));
        channel.nack(msg, false, false);
        return;
      }

      // 4. Dispatch to handler
      const handler = messageHandlers[message.type];
      if (!handler) {
        // This shouldn't happen since we validated the type, but defense in depth
        console.error(`[REJECTED] No handler for type: ${message.type}`);
        channel.nack(msg, false, false);
        return;
      }

      try {
        await handler(message.payload, message.correlationId);
        channel.ack(msg);
      } catch (err) {
        console.error(`[ERROR] Processing ${message.type}: ${err.message}`);
        // Check if message has been redelivered (retry once)
        if (msg.fields.redelivered) {
          console.error(`[DEAD-LETTER] Message already retried, sending to DLQ`);
          await sendToDeadLetter(channel, msg, err);
          channel.nack(msg, false, false);
        } else {
          // Requeue for one retry
          channel.nack(msg, false, true);
        }
      }
    }, { noAck: false });

    // Graceful shutdown
    const shutdown = async (signal) => {
      console.log(`\n[${signal}] Shutting down gracefully...`);
      try {
        await channel.close();
        await connection.close();
        await pool.end();
        console.log('Connections closed.');
        process.exit(0);
      } catch (err) {
        console.error('Error during shutdown:', err.message);
        process.exit(1);
      }
    };

    process.on('SIGINT', () => shutdown('SIGINT'));
    process.on('SIGTERM', () => shutdown('SIGTERM'));

    connection.on('error', (err) => {
      console.error('RabbitMQ connection error:', err.message);
    });

    connection.on('close', () => {
      console.error('RabbitMQ connection closed. Exiting...');
      process.exit(1);
    });

  } catch (err) {
    console.error('Failed to start consumer:', err.message);
    if (connection) {
      try { await connection.close(); } catch (_) {}
    }
    // Retry connection after delay
    console.log('Retrying in 5 seconds...');
    setTimeout(startConsumer, 5000);
  }
}

// --- Health Check HTTP Server ---

const http = require('http');

const healthServer = http.createServer(async (req, res) => {
  if (req.url === '/health' && req.method === 'GET') {
    try {
      await pool.query('SELECT 1');
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ status: 'healthy', timestamp: new Date().toISOString() }));
    } catch (err) {
      res.writeHead(503, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ status: 'unhealthy', error: 'Database connection failed' }));
    }
  } else {
    res.writeHead(404);
    res.end();
  }
});

const healthPort = parseInt(process.env.HEALTH_PORT, 10) || 3000;
healthServer.listen(healthPort, () => {
  console.log(`Health check server listening on port ${healthPort}`);
});

// Start the consumer
startConsumer();

module.exports = { validateMessage, safeParseJSON, messageHandlers };